const coupons = [
  {
    id: 1234567890,
    code: 'DISCOUNT_CODE',
    value: 1000,
    expiresAt: new Date('2020-01-01'),
    used: false,
  },
];

const redeemCoupon = (couponId) => {
  const coupon = coupons.find((c) => c.id === couponId);

  if (!coupon || !coupon.used && new Date() > coupon.expiresAt) return 'Coupon is invalid';

  coupon.used = true;

  return `Successfully redeemed ${coupon.value} points`;
};

